import{_ as e,o as a,c as r,a2 as o}from"./chunks/framework.BEgbRHOA.js";const p=JSON.parse('{"title":"Главная и магазины","description":"","frontmatter":{},"headers":[],"relativePath":"guide/xcourier/home-stores.md","filePath":"guide/xcourier/home-stores.md","lastUpdated":1775746985000}'),d={name:"guide/xcourier/home-stores.md"};function i(l,t,s,n,h,c){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="главная-и-магазины" tabindex="-1">Главная и магазины <a class="header-anchor" href="#главная-и-магазины" aria-label="Permalink to &quot;Главная и магазины&quot;">​</a></h1><h2 id="главная-страница" tabindex="-1">Главная страница <a class="header-anchor" href="#главная-страница" aria-label="Permalink to &quot;Главная страница&quot;">​</a></h2><p>При открытии приложения пользователь попадает на главную страницу, которая содержит:</p><ul><li><strong>Баннеры</strong> — карусель рекламных баннеров в верхней части экрана. Баннеры могут вести на веб-страницу или на страницу магазина.</li><li><strong>Список магазинов</strong> — карточки с логотипом, названием, адресом и временем доставки.</li></ul><p>Данные главной страницы загружаются параллельно (баннеры и магазины) для быстрого отображения. Пока данные грузятся, показывается скелетон-анимация.</p><h2 id="страница-магазина" tabindex="-1">Страница магазина <a class="header-anchor" href="#страница-магазина" aria-label="Permalink to &quot;Страница магазина&quot;">​</a></h2><p>При нажатии на карточку магазина открывается его детальная страница:</p><ul><li>Информация о магазине (название, адрес, телефон, статус работы)</li><li>График работы магазина по дням недели</li><li>Время доставки (например, «30-45 мин»)</li><li>Список товаров магазина с фильтрацией по категориям</li><li>Возможность добавить магазин в избранное</li></ul><h2 id="статусы-магазина" tabindex="-1">Статусы магазина <a class="header-anchor" href="#статусы-магазина" aria-label="Permalink to &quot;Статусы магазина&quot;">​</a></h2><p>Магазин может находиться в одном из четырёх состояний:</p><table tabindex="0"><thead><tr><th>Статус</th><th>Описание</th></tr></thead><tbody><tr><td>Открыт</td><td>Магазин работает, можно заказывать</td></tr><tr><td>Закрыт</td><td>Нерабочее время по расписанию</td></tr><tr><td>Временно закрыт</td><td>Вручную закрыт менеджером</td></tr><tr><td>Недоступен</td><td>Деактивирован администратором</td></tr></tbody></table><p>Если магазин закрыт, оформить заказ нельзя — пользователь увидит соответствующее сообщение.</p>',12)])])}const _=e(d,[["render",i]]);export{p as __pageData,_ as default};
